    std::uint64_t aWandererK = *pWandererK;
    std::uint64_t aNonceWordA = TwistMix64::DiffuseB(pNonce * 0xD16B40AA9BCA89E7ULL + 0xB0BF6796830C27CBULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseA(pNonce * 0x85CF03481798C4FBULL + 0x8C8F14D92844AD63ULL);
    std::uint64_t aNonceWordC = TwistMix64::DiffuseA(pNonce * 0x80BC82681C6A3F97ULL + 0xD12EC042EBD21FDAULL);
    std::uint64_t aNonceWordD = TwistMix64::DiffuseC(pNonce * 0xA36F11AE2E64C033ULL + 0xFB2C9D45C246A117ULL);
    std::uint64_t aNonceWordE = TwistMix64::DiffuseB(pNonce * 0xEB5A9CC4AD82E281ULL + 0x89C83C13A1AB171CULL);
    std::uint64_t aNonceWordF = TwistMix64::DiffuseB(pNonce * 0xD4B11C0EB7FE7FA1ULL + 0xFC2E8ECB1AACD4EAULL);
