            aOrbiterG = (aWandererC + RotL64(aScatter, 57U)) + 0xC4915D61E353F9ECULL;
            aOrbiterB = ((aWandererB + RotL64(aIngress, 29U)) + 0xF667C29F7DC1DB89ULL) + aNonceWordB;
            aOrbiterH = (((aWandererJ + RotL64(aCross, 35U)) + RotL64(aCarry, 5U)) + 0x9D128442D8E196E0ULL) + aNonceWordK;
            aOrbiterF = ((aWandererK + RotL64(aPrevious, 13U)) + RotL64(aCarry, 35U)) + 0x52D6C0C2390BB92DULL;
            aOrbiterD = (((aWandererI + RotL64(aScatter, 24U)) + RotL64(aCarry, 19U)) + 0xA88A3BDBD173E740ULL) + aPhaseAOrbiterAssignSaltE[(((31U - aIndex) + 23U)) & S_SALT1];
            aOrbiterC = (((aWandererD + RotL64(aIngress, 19U)) + 0xC9C8D693E0658890ULL) + aPhaseAOrbiterAssignSaltA[(((31U - aIndex) + 25U)) & S_SALT1]) + aNonceWordH;
            //
            aOrbiterE = (aOrbiterE + aOrbiterA) + 0xEC4D66F5CC2759DCULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterE) ^ 0x1E2B89B5C8179BB8ULL;
            aOrbiterK = RotL64((aOrbiterK * 0xB89F7BA3F50C7475ULL), 27U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterG) + 0x8224611CB50CE78CULL;
            aOrbiterB = ((aOrbiterB ^ aOrbiterK) ^ 0x62D79084A30232A3ULL) ^ aPhaseAOrbiterUpdateSaltA[(((31U - aIndex) + 20U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 0xC9FAC05F260C1C5FULL), 3U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterH) + 0xEB0659D9B76949CDULL;
            aOrbiterG = ((aOrbiterG ^ aOrbiterA) ^ 0x7A98AA435A57B21DULL) ^ aPhaseAOrbiterUpdateSaltB[(((31U - aIndex) + 19U)) & S_SALT1];
            aOrbiterG = RotL64((aOrbiterG * 0x3BD1EDAD084D7EBFULL), 51U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterF) + 0xFB02E6EE13CF177BULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterB) ^ 0x2CE6E49535A36417ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x29B78CC43798A535ULL), 19U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterK) + 0x5F5D8D3909F3DB76ULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 0x115AE47731A12C7FULL;
            aOrbiterC = RotL64((aOrbiterC * 0x464E2F9ABB709573ULL), 39U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterE) + 0xE58CBF6021D0E039ULL) + aNonceWordC;
            aOrbiterD = ((aOrbiterD ^ aOrbiterH) ^ 0x191F223E27BE9ED8ULL) ^ aNonceWordO;
            aOrbiterD = RotL64((aOrbiterD * 0xBCA4207BBE96E56BULL), 11U);
            //
            aOrbiterG = ((aOrbiterG + aOrbiterD) + 0x69A4D7B4736C4E17ULL) + aPhaseAOrbiterUpdateSaltC[((aIndex + 7U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterG) ^ 0x1194E1B6419EDC74ULL;
            aOrbiterF = RotL64((aOrbiterF * 0xF50ABAD7DDB50135ULL), 23U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterB) + 0x91506D8CEEA4808DULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterC) ^ 0xB4514DDA977C19D9ULL;
            aOrbiterA = RotL64((aOrbiterA * 0xF52A60D938F2BE13ULL), 47U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterC) + 0x1876EAC45D4E4678ULL;
            aOrbiterE = ((aOrbiterE ^ aOrbiterF) ^ 0x7F463D18CF2133EEULL) ^ aPhaseAOrbiterUpdateSaltD[(((31U - aIndex) + 13U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 0x7E7F37B59D12B6C5ULL), 43U);
            //
            aIngress = RotL64(aOrbiterK, 29U) ^ aOrbiterG;
            aIngress = aIngress + (RotL64(aOrbiterC, 19U) ^ aOrbiterA);
            aIngress = aIngress + (aOrbiterE ^ RotL64(aOrbiterB, 26U));
            aIngress = aIngress + (aOrbiterD ^ RotL64(aOrbiterF, 41U));
            aIngress = aIngress + RotL64(aOrbiterH, 13U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererA = aWandererA ^ (((RotL64(aCross, 34U) + RotL64(aOrbiterB, 19U)) + aOrbiterC) + aNonceWordM);
            aWandererG = aWandererG + (((RotL64(aScatter, 39U) + aOrbiterF) + RotL64(aOrbiterE, 23U)) + RotL64(aCarry, 5U));
            aWandererB = aWandererB ^ ((((RotL64(aIngress, 43U) + RotL64(aOrbiterC, 14U)) + aOrbiterA) + aNonceWordE) + aPhaseAWandererUpdateSaltD[(((31U - aIndex) + 24U)) & S_SALT1]);
            aWandererD = aWandererD + (((RotL64(aPrevious, 47U) + RotL64(aOrbiterE, 43U)) + aOrbiterA) + RotL64(aCarry, 37U));
            aWandererF = aWandererF ^ ((RotL64(aIngress, 57U) + RotL64(aOrbiterH, 3U)) + aOrbiterK);
