            aOrbiterB = RotL64((aOrbiterB * 0x8091B17907C78A8FULL), 19U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterG) + 0x3B738E15AD8743F0ULL) + aPhaseCOrbiterUpdateSaltD[(((31U - aIndex) + 5U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterI) ^ 0x24CF4085EAF97E6FULL;
            aOrbiterF = RotL64((aOrbiterF * 0x6FA8A9F11ED37E0BULL), 39U);
            //
            aIngress = aOrbiterD ^ RotL64(aOrbiterG, 57U);
