            aIngress = aIngress + (aOrbiterJ ^ RotL64(aOrbiterI, 5U));
            aIngress = aIngress + (RotL64(aOrbiterK, 14U) ^ aOrbiterA);
            aIngress = aIngress + RotL64(aOrbiterF, 27U);
