            //
            aWandererH = aWandererH + (((RotL64(aCross, 53U) + RotL64(aOrbiterE, 35U)) + aOrbiterG) + RotL64(aCarry, 35U));
            aWandererD = aWandererD ^ ((RotL64(aIngress, 6U) + aOrbiterB) + RotL64(aOrbiterI, 27U));
            aWandererJ = aWandererJ + (((RotL64(aScatter, 11U) + RotL64(aOrbiterK, 14U)) + aOrbiterA) + RotL64(aCarry, 23U));
