            aWandererE = aWandererE + (((RotL64(aCross, 57U) + aOrbiterG) + RotL64(aOrbiterA, 39U)) + aPhaseCWandererUpdateSaltB[(((31U - aIndex) + 11U)) & S_SALT1]);
            aWandererI = aWandererI ^ ((RotL64(aPrevious, 30U) + RotL64(aOrbiterF, 43U)) + aOrbiterJ);
            aWandererB = aWandererB + (((RotL64(aScatter, 47U) + aOrbiterK) + RotL64(aOrbiterF, 58U)) + aPhaseCWandererUpdateSaltD[((aIndex + 9U)) & S_SALT1]);
