            //
            aOrbiterD = ((aOrbiterD + aOrbiterI) + 0x546E75AFE48C380DULL) + aPhaseEOrbiterUpdateSaltE[((aIndex + 14U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 0x3AF2BD094DE74B08ULL;
