            //
            aOrbiterK = ((aOrbiterK + aOrbiterD) + 0x7C9B8EDC18D7B0BAULL) + aPhaseEOrbiterUpdateSaltC[(((31U - aIndex) + 28U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterK) ^ 0xFD7EEAF9B8F28256ULL;
            aOrbiterA = RotL64((aOrbiterA * 0x461A80E7B0386315ULL), 21U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterJ) + 0xA96E0E78C49CCDDFULL) + aPhaseEOrbiterUpdateSaltF[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterH = (aOrbiterH ^ aOrbiterC) ^ 0xF5208ED83339D9BBULL;
            aOrbiterH = RotL64((aOrbiterH * 0x6E51B12576160EBFULL), 47U);
