            //
            aOrbiterG = (aWandererK + RotL64(aIngress, 29U)) + 0x268B1C29544405E1ULL;
            aOrbiterA = ((aWandererH + RotL64(aCross, 4U)) + RotL64(aCarry, 35U)) + 0xFB7436ED7D7A70C0ULL;
            aOrbiterF = ((aWandererF + RotL64(aScatter, 51U)) + RotL64(aCarry, 23U)) + 0xA3C7651BE688DC7EULL;
            aOrbiterB = (((aWandererJ + RotL64(aPrevious, 43U)) + RotL64(aCarry, 11U)) + 0x8F867614C07DADF5ULL) + aPhaseFOrbiterAssignSaltB[((aIndex + 25U)) & S_SALT1];
