            aOrbiterK = ((aWandererH + RotL64(aScatter, 51U)) + 0xB2C5D6E595472110ULL) + aPhaseFOrbiterAssignSaltD[((aIndex + 29U)) & S_SALT1];
            aOrbiterJ = ((aWandererK + RotL64(aPrevious, 14U)) + RotL64(aCarry, 53U)) + 0x3D3EC5CEE1409BA6ULL;
            aOrbiterC = (((aWandererG + RotL64(aIngress, 19U)) + RotL64(aCarry, 47U)) + 0xDE3D1AEBDEFAA703ULL) + aPhaseFOrbiterAssignSaltC[(((31U - aIndex) + 17U)) & S_SALT1];
