            aOrbiterD = (aWandererE + RotL64(aScatter, 29U)) + 0xB329F2B079C5D31BULL;
            aOrbiterG = (aWandererF + RotL64(aCross, 24U)) + 0xDB15C67D1F64A290ULL;
