            aOrbiterI = (aOrbiterI + aOrbiterK) + 0xB564F307F74F9CB4ULL;
            aOrbiterF = ((aOrbiterF ^ aOrbiterI) ^ 0xC66D1EC68B36BE22ULL) ^ aPhaseFOrbiterUpdateSaltD[((aIndex + 15U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 0x843260AB960AABDFULL), 3U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterE) + 0x947E059C2DEA2BB4ULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterJ) ^ 0x97098DB66B126C69ULL;
