            aOrbiterA = (aOrbiterA + aOrbiterB) + 0x0426F38CB269A2D5ULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterA) ^ 0xB678508602358C21ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x6790724A34CD328BULL), 43U);
