            aOrbiterB = (((aWandererK + RotL64(aCross, 42U)) + RotL64(aCarry, 29U)) + 0xD7E02CD88B4C53A4ULL) + aPhaseHOrbiterAssignSaltD[((aIndex + 23U)) & S_SALT1];
            aOrbiterK = ((aWandererB + RotL64(aScatter, 23U)) + RotL64(aCarry, 47U)) + 0x48BBBEF1D30B691EULL;
            //
            aOrbiterD = (aOrbiterD + aOrbiterJ) + 0x4FC37C0B712462CAULL;
