            aOrbiterC = RotL64((aOrbiterC * 0x613CF0146A381C6FULL), 47U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterI) + 0xB19F3ED35D07E038ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterA) ^ 0xB35E4CE28F8D43C5ULL;
            aOrbiterE = RotL64((aOrbiterE * 0x34384B2485D4F0DFULL), 13U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterB) + 0xCA15DB7ECCA34FCBULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterG) ^ 0xFB7E1CA8CAB9D0C4ULL;
            aOrbiterA = RotL64((aOrbiterA * 0x31A4D37EACCAD81BULL), 3U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterG) + 0x136B02D3A060D407ULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterC) ^ 0x3C46EAC0B222C176ULL;
            aOrbiterK = RotL64((aOrbiterK * 0xC19BBE998FD8607BULL), 19U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterK) + 0x10A55AB310C9F8AFULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterI) ^ 0x24859CB18CE3D976ULL;
            aOrbiterD = RotL64((aOrbiterD * 0x53311E6495D204F7ULL), 41U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterC) + 0xB25C968B6F7279FDULL) + aPhaseHOrbiterUpdateSaltE[(((31U - aIndex) + 10U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterB) ^ 0xC37CFA2F36B34F8FULL;
